1. 创建相应文件夹并配置环境 //创建文件夹 mkdir -p /scripting-knowledge/{scripts,data,logs} cd /scripting-knowledge &amp;&amp; ls -la //配置python虚拟环境 cd /scripting-knowledge &amp;&amp; python3 -m venv venv source venv/bin/activate &amp;&amp; pip install --upgrade pip //安装必要的包 pip install chromadb llama-index beautifulsoup4 requests lxml 1.1. 为什么要配置虚拟python环境 避免依赖冲突 不影响系统自带python（因为是在mac中，mac系统自带的比较重要） 依赖管理清晰 权限问题，虚拟环境不需要sudo 2. 编写Python脚本 #!/usr/bin/env python3 &#34;&#34;&#34; Scripting.fun 文档抓取器 从 https://scripting.fun/doc_v2/zh/guide/ 抓取所有文档内容 策略： 1. 用 Playwright 加载一次页面，从侧边栏提取所有文档链接 2. 用 requests + .html 后缀批量抓取 SSR 内容（快速） &#34;&#34;&#34; import requests from bs4 import BeautifulSoup import json import hashlib import time from pathlib import Path class ScriptingDocScraper: def __init__(self, output_path=None): self.site_root = &#34;https://scripting.fun&#34; self.entry_url = &#34;https://scripting.fun/doc_v2/zh/guide/Quick%20Start&#34; self.sidebar_selector = &#34;#__rspress_root &gt; div.rp-doc-layout__container &gt; aside.rp-doc-layout__sidebar&#34; self.visited = set() self.docs = [] self.output_path = output_path # 加载已有数据，建立 url -&gt; {doc, content_hash} 的索引 self.existing = {} if output_path and Path(output_path).exists(): with open(output_path, &#34;r&#34;, encoding=&#34;utf-8&#34;) as f: for doc in json.load(f): h = hashlib.md5(doc[&#34;content&#34;].encode()).hexdigest() self.existing[doc[&#34;url&#34;]] = {&#34;doc&#34;: doc, &#34;hash&#34;: h} print(f&#34;已加载 {len(self.existing)} 篇已有文档&#34;) def discover_urls(self): &#34;&#34;&#34;用 Playwright 加载页面，从侧边栏提取所有文档链接&#34;&#34;&#34; from playwright.sync_api import sync_playwright discovered = set() print(&#34;正在用 Playwright 加载侧边栏...&#34;) try: with sync_playwright() as p: browser = p.chromium.launch(headless=True) page = browser.new_page() page.goto(self.entry_url, wait_until=&#34;networkidle&#34;, timeout=30000) sidebar = page.query_selector(self.sidebar_selector) if not sidebar: print(&#34; 未找到侧边栏元素，尝试等待...&#34;) page.wait_for_selector(self.sidebar_selector, timeout=10000) sidebar = page.query_selector(self.sidebar_selector) if sidebar: links = sidebar.query_selector_all(&#34;a[href]&#34;) for link in links: href = link.get_attribute(&#34;href&#34;) if href and &#34;/guide/&#34; in href: # 将英文路径转为中文版路径 path = href if &#34;/doc_v2/guide/&#34; in path and &#34;/doc_v2/zh/guide/&#34; not in path: path = path.replace(&#34;/doc_v2/guide/&#34;, &#34;/doc_v2/zh/guide/&#34;) # 构建 .html 后缀的完整 URL if path.endswith(&#34;/&#34;): html_path = path + &#34;index.html&#34; else: html_path = path + &#34;.html&#34; full_url = f&#34;{self.site_root}{html_path}&#34; discovered.add(full_url) print(f&#34; 从侧边栏发现 {len(discovered)} 个文档页面&#34;) else: print(&#34; 未找到侧边栏&#34;) browser.close() except Exception as e: print(f&#34; Playwright 加载失败: {e}&#34;) return discovered def extract_content(self, soup): &#34;&#34;&#34;提取页面主要内容&#34;&#34;&#34; # 移除脚本和样式 for script in soup([&#34;script&#34;, &#34;style&#34;, &#34;nav&#34;, &#34;footer&#34;]): script.decompose() # 尝试找到主要内容区域 main_content = (soup.find(&#34;main&#34;) or soup.find(&#34;article&#34;) or soup.find(class_=&#34;content&#34;) or soup.find(class_=&#34;markdown-body&#34;)) if main_content: text = main_content.get_text(separator=&#34;
&#34;, strip=True) else: text = soup.get_text(separator=&#34;
&#34;, strip=True) # 清理空行 lines = [line.strip() for line in text.split(&#34;
&#34;) if line.strip()] return &#34;
&#34;.join(lines) def scrape_page(self, url): &#34;&#34;&#34;抓取单个页面（增量：跳过内容未变化的页面）&#34;&#34;&#34; if url in self.visited: return False self.visited.add(url) try: response = requests.get(url, timeout=10) if response.status_code in (403, 404, 410): print(f&#34; 跳过 (HTTP {response.status_code}): {url}&#34;) return False response.raise_for_status() response.encoding = &#34;utf-8&#34; soup = BeautifulSoup(response.text, &#34;html.parser&#34;) title = soup.find(&#34;h1&#34;) title_text = title.get_text(strip=True) if title else url content = self.extract_content(soup) if not content or len(content) &lt; 10: print(f&#34; 跳过 (内容为空): {url}&#34;) return False # 增量判断：内容哈希相同则跳过 content_hash = hashlib.md5(content.encode()).hexdigest() if url in self.existing and self.existing[url][&#34;hash&#34;] == content_hash: # 内容未变，沿用旧数据 self.docs.append(self.existing[url][&#34;doc&#34;]) return False doc = { &#34;url&#34;: url, &#34;title&#34;: title_text, &#34;content&#34;: content } self.docs.append(doc) return True # 标记为新增/更新 except Exception as e: print(f&#34; 错误 {url}: {e}&#34;) # 出错时保留旧数据 if url in self.existing: self.docs.append(self.existing[url][&#34;doc&#34;]) return False def scrape_all(self): &#34;&#34;&#34;增量抓取所有页面&#34;&#34;&#34; urls = self.discover_urls() if not urls: print(&#34;未发现任何文档页面，请检查网站是否可访问&#34;) return self.docs, False url_list = sorted(urls) total = len(url_list) updated = 0 skipped = 0 print(f&#34;
开始抓取 {total} 个页面（已有 {len(self.existing)} 篇）...
&#34;) for i, url in enumerate(url_list, 1): is_new = self.scrape_page(url) if is_new: updated += 1 print(f&#34; [{i}/{total}] 新增/更新: {url}&#34;) else: skipped += 1 time.sleep(0.3) # 检测已删除的页面（旧数据中有，但侧边栏中不再存在） removed = set(self.existing.keys()) - urls if removed: print(f&#34;
检测到 {len(removed)} 篇已删除的页面&#34;) has_changes = updated &gt; 0 or len(removed) &gt; 0 print(f&#34;
完成! 共 {len(self.docs)} 篇 | 新增/更新: {updated} | 未变化: {skipped} | 删除: {len(removed)}&#34;) return self.docs, has_changes def save_to_json(self, output_path): &#34;&#34;&#34;保存为 JSON 文件&#34;&#34;&#34; with open(output_path, &#34;w&#34;, encoding=&#34;utf-8&#34;) as f: json.dump(self.docs, f, ensure_ascii=False, indent=2) print(f&#34;已保存到: {output_path}&#34;) if __name__ == &#34;__main__&#34;: data_dir = Path(__file__).parent.parent / &#34;data&#34; data_dir.mkdir(exist_ok=True) output_file = data_dir / &#34;scripting_docs.json&#34; scraper = ScriptingDocScraper(output_path=output_file) docs, has_changes = scraper.scrape_all() if has_changes: scraper.save_to_json(output_file) print(&#34;文档已更新&#34;) else: print(&#34;无变化，跳过写入&#34;)

1. 定义 Singleton是一种创建型设计模式，确保一个类只有一个实例，并提供一个全局唯一的访问点来获取该实例。
2. 核心特点 唯一实例 全局访问 延迟初始化 3. 常用实现方式 public class Singleton { private static Singleton _instance; private Singleton() { Console.WriteLine(&#34;实例被创建&#34;); } public static Singleton Instance { get { if (_instance == null) // ← 线程A检查：null { // ← 线程B检查：null（同时进入） _instance = new Singleton(); // ← 两个线程都执行创建！ } return _instance; } } } 如果同时有两个线程创建实例，同时检查null，会导致创建两个实例，违反单例原则。 4. 线程安全的解决方案 4.1. Lazy&lt; T &gt; public class Singleton { // Lazy&lt;T&gt; 内部自动处理线程安全 private static readonly Lazy&lt;Singleton&gt; _instance = new Lazy&lt;Singleton&gt;(() =&gt; new Singleton()); private Singleton() { Console.WriteLine(&#34;实例被创建 - 只会执行一次&#34;); } public static Singleton Instance =&gt; _instance.Value; } 4.2. 使用lock锁 public class Singleton { private static Singleton _instance; private static readonly object _lock = new object(); private Singleton() { } public static Singleton Instance { get { lock (_lock) // ← 同一时间只有一个线程能进入 { if (_instance == null) { _instance = new Singleton(); } return _instance; } } } } 以上只是针对c#来说，在unity中，因为要基于Monobehaviour，所以有些许不同。
//在简单的项目中，可以通过if判断，以及DontDestroyOnLoad来设置单例 using UnityEngine; public class GameManager : MonoBehaviour { public static GameManager Instance { get; private set; } private void Awake() { // 防止重复实例 if (Instance != null &amp;&amp; Instance != this) { Destroy(gameObject); return; } Instance = this; DontDestroyOnLoad(gameObject); // 场景切换时不销毁 } } 在大型项目中，亦可创建泛型单例基类，当然适用于所有项目
using UnityEngine; //abstract 抽象类；Singleton&lt;T&gt; 泛型；`:MonoBehaviour` 继承MonoBehaviour； where T : MonoBehaviour 泛型约束，限制 `T` 必须是 MonoBehaviour 的子类 public abstract class Singleton&lt;T&gt; : MonoBehaviour where T : MonoBehaviour { private static T _instance; private static readonly object _lock = new object(); private static bool _applicationIsQuitting = false; public static T Instance { get { if (_applicationIsQuitting) { return null; } lock (_lock) { if (_instance == null) { _instance = FindObjectOfType&lt;T&gt;(); if (_instance == null) { GameObject obj = new GameObject(); _instance = obj.AddComponent&lt;T&gt;(); obj.name = $&#34;[Singleton] {typeof(T).Name}&#34;; DontDestroyOnLoad(obj); } } return _instance; } } } protected virtual void Awake() { if (_instance != null &amp;&amp; _instance != this) { Destroy(gameObject); return; } _instance = this as T; DontDestroyOnLoad(gameObject); OnAwake(); // 子类初始化 } // 子类重写此方法进行初始化 protected virtual void OnAwake() { } protected virtual void OnApplicationQuit() { _applicationIsQuitting = true; } }

1 什么是GC 垃圾回收是自动内存管理机制，负责自动释放不再使用的内存，防止内存泄漏。
2 基本概念 根对象：静态字段、局部变量、CPU寄存器等 可达性：从根对象直接或间接引用的对象 代际理论：对象生存期越短，越应该被快速回收 3 Net/Unity三代GC Generation 0 ：新创建的对象15:01 Generation 1 ：存货过一次的gc对象 Generation 2: 长期存活的对象 4 GC触发时机 第0代满时 手动调用GC.Collect（） 系统内存不足 应用程序卸载域 5 主要GC来源 using UnityEngine;
using System.Collections;
public class GCExample : MonoBehaviour
{
void Update()
{
// 1. 字符串拼接
string result = &quot;Score: &quot; + score + &quot; Time: &quot; + time; // 产生GC
// 2. 装箱操作
int number = 42;
object boxed = number; // 装箱，产生GC
// 3. LINQ查询
var filtered = someList.Where(x =&gt; x &gt; 10).ToList(); // 产生GC
// 4. 匿名方法/Lambda
someList.ForEach(x =&gt; Debug.Log(x)); // 可能产生GC
// 5. 数组分配
Vector3[] tempArray = new Vector3[100]; // 产生GC
}
}
6 GC优化技巧 6.1 避免在循环中分配内存 6.2 使用对象池，避免频繁的Instantiate/Destory 6.3 避免装箱操作 6.4 缓存组件和对象 6.5 使用结构体替代类 6.6 使用Array代替List 6.7 避免在update中使用Find
